# v2 - APC Champions League
"""
auth.py
"""
import streamlit as st
from data_layer import verify_login, load_all
from config import ADMIN_ID

LOGO_B64 = ""

def ensure_session_defaults():
    defaults = {
        "authenticated": False,
        "team_id":       None,
        "team_name":     None,
        "is_admin":      False,
        "active_page":   "home",
        "show_help":     False,
        "view_team_id":  None,
    }
    for k, v in defaults.items():
        if k not in st.session_state:
            st.session_state[k] = v


def render_login(conn):
    st.markdown("""
    <style>
    .login-wrap {
        max-width: 400px;
        margin: 40px auto 0;
        text-align: center;
    }
    .login-title {
        font-family: 'Barlow Condensed', sans-serif;
        font-size: 1.5rem;
        font-weight: 800;
        letter-spacing: 0.1em;
        color: #27C878;
        margin: 8px 0 2px;
    }
    .login-sub {
        font-size: 1.8rem;
        font-weight: 900;
        color: #ffffff;
        letter-spacing: 0.05em;
        margin-bottom: 28px;
    }
    .login-footer {
        text-align: center;
        margin-top: 20px;
        color: #3D4A60;
        font-size: 0.72rem;
    }
    </style>
    """, unsafe_allow_html=True)

    _, col, _ = st.columns([1, 2, 1])
    with col:
        st.markdown(
            f'''<div class="login-wrap">
              <img src="data:image/png;base64,{LOGO_B64}"
                   style="width:160px;filter:drop-shadow(0 0 16px rgba(39,200,120,0.5));">
              <div class="login-title">APC CHAMPIONS</div>
              <div class="login-sub">LEAGUE</div>
            </div>''',
            unsafe_allow_html=True,
        )

        tid = st.text_input("ID da Equipa", placeholder="ex: EQ001", key="login_tid").strip()
        pw  = st.text_input("Password", type="password", key="login_pw")

        if st.button("▶  Entrar", width='stretch', key="login_btn"):
            data = load_all(conn)
            user = verify_login(data["teams"], tid, pw)
            if user:
                st.session_state.authenticated = True
                st.session_state.team_id       = tid
                st.session_state.team_name     = user.get("team_name", tid)
                st.session_state.is_admin      = (
                    tid == ADMIN_ID or
                    str(user.get("is_admin", "")).upper() == "TRUE"
                )
                my_matches = data["matches"]
                if not my_matches.empty:
                    pend = my_matches[
                        (my_matches["team_b_id"] == tid) &
                        (my_matches["validation_status"] == "pending")
                    ]
                    if not pend.empty:
                        st.session_state.active_page = "challenges"
                st.rerun()
            else:
                st.error("Credenciais inválidas.")

    st.markdown(
        '<div class="login-footer">Powered by Sir-ILO &copy; 2026</div>',
        unsafe_allow_html=True,
    )
